import{_ as t,o as i,c as a,ag as o}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md"}'),r={name:"guide/getting-started.md"};function n(l,e,s,d,g,c){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This guide walks you through installing SendGrail and sending your first authenticated email.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><h3 id="from-wordpress-admin" tabindex="-1">From WordPress Admin <a class="header-anchor" href="#from-wordpress-admin" aria-label="Permalink to &quot;From WordPress Admin&quot;">​</a></h3><ol><li>Go to <strong>Plugins &gt; Add New</strong> in your WordPress dashboard.</li><li>Search for <strong>SendGrail</strong>.</li><li>Click <strong>Install Now</strong>, then <strong>Activate</strong>.</li></ol><h3 id="manual-upload" tabindex="-1">Manual Upload <a class="header-anchor" href="#manual-upload" aria-label="Permalink to &quot;Manual Upload&quot;">​</a></h3><ol><li>Download the <code>sendgrail.zip</code> file from <a href="https://wordpress.org/plugins/sendgrail/" target="_blank" rel="noreferrer">WordPress.org</a>.</li><li>Go to <strong>Plugins &gt; Add New &gt; Upload Plugin</strong>.</li><li>Choose the zip file and click <strong>Install Now</strong>.</li><li>Click <strong>Activate</strong>.</li></ol><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><p>After activation, you will be automatically redirected to the <strong>Setup Wizard</strong>. The wizard guides you through five steps:</p><ol><li><strong>Welcome</strong> -- Overview of what SendGrail does.</li><li><strong>Migration</strong> -- Auto-detects settings from other SMTP plugins (if any).</li><li><strong>Configure</strong> -- Pick your SMTP provider and enter credentials.</li><li><strong>Test</strong> -- Send a test email to verify everything works.</li><li><strong>Done</strong> -- Confirmation that your site is ready.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>If you prefer to skip the wizard, click &quot;Skip&quot; on the welcome screen. You can always configure connections manually from the dashboard.</p></div><p>For a detailed breakdown of each wizard step, see the <a href="/guide/setup-wizard">Setup Wizard</a> page.</p><h2 id="creating-a-connection-manually" tabindex="-1">Creating a Connection Manually <a class="header-anchor" href="#creating-a-connection-manually" aria-label="Permalink to &quot;Creating a Connection Manually&quot;">​</a></h2><p>If you skipped the wizard or want to add additional connections:</p><ol><li>Navigate to <strong>SendGrail</strong> in the WordPress admin sidebar.</li><li>Click the <strong>Connections</strong> tab.</li><li>Click <strong>Add Connection</strong>.</li><li>Select your SMTP provider from the dropdown. The host, port, and encryption fields will be pre-filled.</li><li>Enter your credentials: <ul><li><strong>From Email</strong> -- The sender email address.</li><li><strong>From Name</strong> -- The sender display name.</li><li><strong>Username</strong> -- Your SMTP username.</li><li><strong>Password</strong> -- Your SMTP password or API key.</li></ul></li><li>Click <strong>Save Connection</strong>.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Some providers (like Gmail and Yahoo) require an <strong>App Password</strong> instead of your regular account password. See the <a href="/guide/providers">SMTP Providers</a> page for provider-specific instructions.</p></div><h2 id="sending-a-test-email" tabindex="-1">Sending a Test Email <a class="header-anchor" href="#sending-a-test-email" aria-label="Permalink to &quot;Sending a Test Email&quot;">​</a></h2><p>After saving a connection, verify it works:</p><ol><li>Go to the <strong>Connections</strong> tab.</li><li>Find your connection in the list and click <strong>Test</strong>.</li><li>Enter a recipient email address.</li><li>Click <strong>Send Test Email</strong>.</li><li>Check the recipient&#39;s inbox (and spam folder) for the test message.</li></ol><p>A successful test confirms that your SMTP credentials are correct, the connection is working, and emails will be delivered through this provider.</p><h2 id="setting-as-default" tabindex="-1">Setting as Default <a class="header-anchor" href="#setting-as-default" aria-label="Permalink to &quot;Setting as Default&quot;">​</a></h2><p>To make a connection the default for all outgoing WordPress emails:</p><ol><li>Go to <strong>Settings &gt; General</strong>.</li><li>Under <strong>Default Connection</strong>, select your connection from the dropdown.</li><li>Click <strong>Save Settings</strong>.</li></ol><p>All calls to <code>wp_mail()</code> from WordPress core, plugins, and themes will now route through this connection.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/guide/fallback">Configure a fallback connection</a> for reliability.</li><li><a href="/guide/settings">Review all available settings</a> including email logging and tracking.</li><li><a href="/guide/providers">Learn about all 13+ supported providers</a>.</li></ul>',26)])])}const p=t(r,[["render",n]]);export{h as __pageData,p as default};
